type UxTaskFunc func(context.Context, *ent.UxTaskMutation) (ent.Value, error)

// Mutate calls f(ctx, m).
func (f UxTaskFunc) Mutate(ctx context.Context, m ent.Mutation) (ent.Value, error) {
	if mv, ok := m.(*ent.UxTaskMutation); ok {
		return f(ctx, mv)
	}
	return nil, fmt.Errorf("unexpected mutation type %T. expect *ent.UxTaskMutation", m)
}

